mapper.update:
UPDATE address
SET is_default = 0
WHERE user_id = #{userId}

mapper.select:
SELECT id, user_id, name, phone, province, city, district, detail, is_default, create_time, update_time
FROM address
WHERE id = #{id}
  AND user_id = #{userId}

mapper.delete:
DELETE FROM address
WHERE id = #{id}
  AND user_id = #{userId}
